    }
}

int lca(int u, int v) {
    if (dep[top[u]] < dep[top[v]]) swap(u, v);
    while (top[u] != top[v]) {
        u = f[top[u]];
        if (dep[top[u]] < dep[top[v]]) swap(u, v);
    }
    if (dep[u] < dep[v]) swap(u, v);
    return v;
}

void discretize() {
    sort(v.begin(), v.end());
    for (int i = 1; i <= n; i++)
        val[i] = lower_bound(v.begin(), v.end(), val[i]) - v.begin() + 1;
}

void modify(int now) {
    if (!vis[now]) {
        ++cntC[val[now]];
        if (cntC[val[now]] == 1) tot++;
    } else {
        --cntC[val[now]];
        if (cntC[val[now]] == 0) tot--;
    }
    vis[now] ^= 1;
}

int main() {
    read(n), read(m);
