# P4074 [WC2013]糖果公园
## Description
[题目链接](https://www.luogu.com.cn/problem/P4074)
## Hint
记录每个询问之前的修改次数，排序的时候以修改次数为第三关键字排序即可。查询的时候，如果多修改了则回退，否则对未修改的部分进行修改，当修改位置在本次查询区间内时对答案进行更新。
## Solution1
求欧拉序后转化为区间问题。
## Code1
```cpp 糖果公园（欧拉序）
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int MAXN = 1e5 + 5;
int n, m, Q, B, type, cntQ, cntR;
int C[MAXN], V[MAXN], W[MAXN];
ll tot, ans[MAXN];
int p[MAXN], in[MAXN], out[MAXN], from[MAXN * 2];
int belong[MAXN * 2], cntC[MAXN];
int hson[MAXN], sz[MAXN], dep[MAXN], f[MAXN], top[MAXN];
bool vis[MAXN];

template <class T>
void read(T &x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Edge {
    int to, nxt;
} e[MAXN * 2];

struct Query {
    int l, r, id, lca, t;
    friend bool operator<(const Query &a, const Query &b) {
        if (belong[a.l] == belong[b.l]) {
            if (belong[a.r] == belong[b.r]) return a.t < b.t;
            if (belong[a.l] & 1) return belong[a.r] < belong[b.r];
            return belong[a.r] > belong[b.r];
        }
        return belong[a.l] < belong[b.l];
    }
} q[MAXN];

struct Replace {
    int id, type;
} r[MAXN];

void addEdge(int from, int to) {
    static int t;
    e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}

void dfs(int now, int fa) {
    static int tim = 1;
    in[now] = tim, from[tim++] = now;
    sz[now] = 1, dep[now] = dep[fa] + 1, f[now] = fa;
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != fa) {
            dfs(to, now);
            sz[now] += sz[to];
            if (!hson[now] || sz[to] > sz[hson[now]]) hson[now] = to;
        }
    }
    out[now] = tim, from[tim++] = now;
}

void dfs2(int now, int tp) {
    top[now] = tp;
    if (!hson[now]) return;
    dfs2(hson[now], tp);
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != f[now] && to != hson[now]) dfs2(to, to);
    }
}

int lca(int u, int v) {
    if (dep[top[u]] < dep[top[v]]) swap(u, v);
    while (top[u] != top[v]) {
        u = f[top[u]];
        if (dep[top[u]] < dep[top[v]]) swap(u, v);
    }
    if (dep[u] < dep[v]) swap(u, v);
    return v;
}

void modify(int now) {
    if (!vis[now]) {
        ++cntC[C[now]];
        tot += 1ll * W[cntC[C[now]]] * V[C[now]];
    } else {
        tot -= 1ll * W[cntC[C[now]]] * V[C[now]];
        --cntC[C[now]];
    }
    vis[now] ^= 1;
}

void change(Replace &rep) {
    if (vis[rep.id]) {
        modify(rep.id);
        swap(rep.type, C[rep.id]);
        modify(rep.id);
    } else
        swap(rep.type, C[rep.id]);
}

int main() {
    read(n), read(m), read(Q);
    fill(p + 1, p + n + 1, -1);
    for (int i = 1; i <= m; i++) read(V[i]);
    for (int i = 1; i <= n; i++) read(W[i]);
    int x, y, t;
    for (int i = 1; i <= n - 1; i++) {
        read(x), read(y);
        addEdge(x, y), addEdge(y, x);
    }
    for (int i = 1; i <= n; i++) read(C[i]);
    B = pow(n, 2.0 / 3);  //不要忘了.0!
    dfs(1, 1), dfs2(1, 1);
    for (int i = 1; i <= Q; i++) {
        read(type);
        if (type == 1) {
            cntQ++;
            read(x), read(y);
            if (in[x] > in[y]) swap(x, y);
            q[cntQ].lca = lca(x, y);
            if (q[cntQ].lca == x) {
                q[cntQ].l = in[x];
                q[cntQ].r = in[y];
                q[cntQ].lca = 0;
            } else {
                q[cntQ].l = out[x];
                q[cntQ].r = in[y];
            }
            q[cntQ].id = cntQ;
            q[cntQ].t = cntR;
        } else {
            cntR++;
            read(x), read(y);
            r[cntR].id = x, r[cntR].type = y;
        }
    }
    for (int i = 1; i <= 2 * n; i++) belong[i] = (i - 1) / B + 1;
    sort(q + 1, q + cntQ + 1);
    x = 1, y = 0, t = 0;
    for (int i = 1; i <= cntQ; i++) {
        while (x < q[i].l) modify(from[x++]);
        while (x > q[i].l) modify(from[--x]);
        while (y > q[i].r) modify(from[y--]);
        while (y < q[i].r) modify(from[++y]);
        while (t < q[i].t) change(r[++t]);
        while (t > q[i].t) change(r[t--]);
        if (q[i].lca) modify(q[i].lca);
        ans[q[i].id] = tot;
        if (q[i].lca) modify(q[i].lca);
    }
    for (int i = 1; i <= cntQ; i++) printf("%lld\n", ans[i]);
    return 0;
}
