int hson[MAXN], sz[MAXN], dep[MAXN], f[MAXN], top[MAXN];
bool vis[MAXN];

template <class T>
void read(T &x, T f = 1, char ch = getchar()) {
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct Edge {
    int to, nxt;
} e[MAXN * 2];

struct Query {
    int x, y, id, t;
    friend bool operator<(const Query &a, const Query &b) {
        if (belong[a.x] == belong[b.x]) {
            if (belong[a.y] == belong[b.y]) return a.t < b.t;
            if (belong[a.x] & 1) return belong[a.y] < belong[b.y];
            return belong[a.y] > belong[b.y];
        }
        return belong[a.x] < belong[b.x];
    }
} q[MAXN];

struct Replace {
    int id, type;
} r[MAXN];

void addEdge(int from, int to) {
    static int t;
    e[t].to = to, e[t].nxt = p[from], p[from] = t++;
}

stack<int> s;
void dfs(int now, int fa) {
    sz[now] = 1, dep[now] = dep[fa] + 1, f[now] = fa;
    int tmp = s.size();
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != fa) {
            dfs(to, now);
            sz[now] += sz[to];
            if (!hson[now] || sz[to] > sz[hson[now]]) hson[now] = to;
            if (s.size() - tmp >= B) {
                cntB++;
                while (s.size() > tmp) {
                    int cur = s.top();
                    s.pop();
                    belong[cur] = cntB;
                }
            }
        }
    }
    s.push(now);
}

void dfs2(int now, int tp) {
    top[now] = tp;
    if (!hson[now]) return;
    dfs2(hson[now], tp);
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (to != f[now] && to != hson[now]) dfs2(to, to);
    }
}

int lca(int u, int v) {
    if (dep[top[u]] < dep[top[v]]) swap(u, v);
    while (top[u] != top[v]) {
        u = f[top[u]];
        if (dep[top[u]] < dep[top[v]]) swap(u, v);
    }
    if (dep[u] < dep[v]) swap(u, v);
    return v;
}

void getBlock() {
    B = sqrt(n);
    dfs(1, 1);
    dfs2(1, 1);
    if (!cntB) ++cntB;
    while (!s.empty()) {
        int tmp = s.top();
        s.pop();
        belong[tmp] = cntB;
    }
}

void modify(int now) {
    if (!vis[now]) {
        ++cntC[C[now]];
        tot += 1ll * W[cntC[C[now]]] * V[C[now]];
    } else {
        tot -= 1ll * W[cntC[C[now]]] * V[C[now]];
        --cntC[C[now]];
    }
    vis[now] ^= 1;
}

void update(int u, int v) {
    if (dep[u] < dep[v]) swap(u, v);
    while (dep[u] > dep[v]) modify(u), u = f[u];
    while (u != v) modify(u), modify(v), u = f[u], v = f[v];
}

void change(Replace &rep) {
    if (vis[rep.id]) {
        modify(rep.id);
        swap(rep.type, C[rep.id]);
        modify(rep.id);
    } else
        swap(rep.type, C[rep.id]);
}

int main() {
    read(n), read(m), read(Q);
    fill(p + 1, p + n + 1, -1);
    for (int i = 1; i <= m; i++) read(V[i]);
    for (int i = 1; i <= n; i++) read(W[i]);
    int x, y, t;
    for (int i = 1; i <= n - 1; i++) {
        read(x), read(y);
        addEdge(x, y), addEdge(y, x);
    }
    for (int i = 1; i <= n; i++) read(C[i]);
    B = pow(n, 2.0 / 3);
    getBlock();
    for (int i = 1; i <= Q; i++) {
        read(type);
        if (type == 1) {
            cntQ++;
            read(x), read(y);
            q[cntQ].x = x, q[cntQ].y = y;
            q[cntQ].id = cntQ;
            q[cntQ].t = cntR;
        } else {
            cntR++;
            read(x), read(y);
            r[cntR].id = x, r[cntR].type = y;
        }
    }
    sort(q + 1, q + cntQ + 1);
    x = 1, y = 1, t = 0;
    modify(1);
    for (int i = 1; i <= cntQ; i++) {
        int lca1 = lca(x, y), lca2 = lca(q[i].x, q[i].y);
        update(x, q[i].x), x = q[i].x;
        update(y, q[i].y), y = q[i].y;
        modify(lca1), modify(lca2);
        while (t < q[i].t) change(r[++t]);
        while (t > q[i].t) change(r[t--]);
        ans[q[i].id] = tot;
    }
    for (int i = 1; i <= cntQ; i++) printf("%lld\n", ans[i]);
    return 0;
}
```

# World of Darkraft-Battle for Azathoth
  - [题目链接](https://www.luogu.com.cn/problem/CF1320C)
  - 数据结构/线段树

<!-- more -->
# Description
给定 n 种武器(攻击为 $x_i$， 价格为 $c_i$)，m 种(防御为 $y_j$，$c_j$)防具， p 个怪物(防御为 $x_k$， 攻击 $y_k$， 金币 $z_k$)。

你必须选择一个武器(攻击力为 $x$)和一个防具(防御为 $y$)， 一个怪物 $k$ 能被击杀，当且仅当 $x > x_k$ 并且 $y > y_k$。求最大收益(可能为负)。
# Solution
  - 将怪物按照防御 $y_k$ 排序，从小到大处理(类似扫描线)。
    ```cpp
    for (int i = 0, v, c; i < n; i++) //武器与怪物防御力放在一起排序
        read(v), read(c), vec.emplace_back(make_pair(v - 1, make_pair(Inf, c)));
    for(...) vec.emplace_back(make_pair(def, make_pair(atk, c)));
    ```
  - 找到最小的 $j$ 使得 $y_j > y_k$，则编号 $\ge j$ 的所有防具获得的金币 $D_j$ 都加上 $z_k$(金币初始值为 $-c_j$)。
  - upper_bound 找到 $x_i > x$， 则最大获利为$-c_i + \max D_j$。
  - 按防具下标建立线段树维护最大值, 支持区间增值即可。

注意：
  - 最大收益可能为-2e9。
  - 对pair排序以及upper_bound, 为防止临时变量第二关键值影响需将其设为Inf
  ``int pos = upper_bound(armor.begin(), armor.end(), make_pair(y, Inf)) - armor.begin();``
# Code
```cpp World of Darkraft-Battle for Azathoth
#include <bits/stdc++.h>

constexpr int MAXN = 2e5 + 5;
constexpr int Inf = 0x7fffffff;

using namespace std;
using LL = long long;

template <typename T>
inline void read(T &x) {
    int f = 1;
    x = 0;
    char ch = getchar();
    while (!isdigit(ch)) f = (ch == '-') ? -1 : 1, ch = getchar();
    while (isdigit(ch)) x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct segTree {
    segTree *Lson, *Rson;
    int l, r;
    int max, tag;
} Tree[MAXN << 1];
int tot, n, m, p, ans = -Inf;
vector<pair<int, int> > weapon, armor;
vector<pair<int, pair<int, int> > > vec;

using Node = segTree *;
#define Lson root->Lson
#define Rson root->Rson
inline void build(int L, int R, Node root) {
    root->l = L, root->r = R;
    if (L == R) {
        root->max = -armor[L].second;
        return;
    }
    int mid = (L + R) >> 1;
    Lson = &Tree[++tot], Rson = &Tree[++tot];
    build(L, mid, Lson), build(mid + 1, R, Rson);
    root->max = max(Lson->max, Rson->max);
}

inline void pushTag(Node root) {
    if (!root->tag) return;
    Lson->tag += root->tag, Lson->max += root->tag;
    Rson->tag += root->tag, Rson->max += root->tag;
    root->tag = 0;
}

inline void change(int L, int R, int val, Node root) {
    if (L <= root->l && root->r <= R) {
        root->max += val, root->tag += val;
        return;
    }
    pushTag(root);
    int mid = (root->l + root->r) >> 1;
    if (L <= mid) change(L, R, val, Lson);
    if (R > mid) change(L, R, val, Rson);
    root->max = max(Lson->max, Rson->max);
}

int main() {
    read(n), read(m), read(p);
    for (int i = 0, v, c; i < n; i++)  //武器与怪物防御力放在一起排序
        read(v), read(c), vec.emplace_back(make_pair(v - 1, make_pair(Inf, c)));
    for (int i = 0, v, c; i < m; i++)
        read(v), read(c), armor.emplace_back(make_pair(v, c));
    sort(armor.begin(), armor.end());  //防具按防御值升序排序
    build(0, m - 1, Tree);             //按防具下标建树
    for (int i = 0, def, atk, c; i < p; i++) {
        read(def), read(atk), read(c);
        vec.emplace_back(make_pair(def, make_pair(atk, c)));
    }
    sort(vec.begin(), vec.end());
    for (auto &i : vec) {
        int x = i.first, y = i.second.first, c = i.second.second;
        if (y == Inf) {  // y = inf表明这是一个武器
            ans = max(ans, -c + Tree->max);
            continue;
        }
        int pos = upper_bound(armor.begin(), armor.end(), make_pair(y, Inf)) -
                  armor.begin();
        if (pos < m) change(pos, m - 1, c, Tree);  //后缀区间增值
    }
    cout << ans << endl;
    return 0;
}
```

# Navigation System
  - [题目链接](https://www.luogu.com.cn/problem/CF1320B)
  - 图论/最短路
  - 贪心
<!-- more -->
# Solution
Rebuild 最少：若有多条最短路，让每次导航恰好取和工作路径部分重合或完全重合的最短路。如果当前节点经工作路径到终点的距离大于到该点的最短路，且该节点到终点的最短路、工作路径没有公共前缀，一定会 Rebuild，有交集就不 Rebuild; 如果工作路径和最短路完全重合，则不会再 Rebuild，beak即可。

Rebuild 最多：若有多条最短路，让每次导航优尽量取在工作路径外的最短路。如果当前节点经工作路径到终点的距离大于到该点的最短路，且该节点到终点的最短路、工作路径没有公共前缀，一定 Rebuild ; 若当前节点经工作路径到终点的距离等于到该点的最短路，且有多条最短路优先取工作路径以外的, 若仅有一条最短路，即只能取在工作路径上的，则不会再 Rebuild，beak即可。

# Code
```cpp Navigation System
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 2e5 + 5;

int n, m, c;
vector<int> G[MAXN];
array<int, MAXN> dis, inq, id, onChain, outChain, chain, chainDis;

inline void spfa(int st) {
    fill(dis.begin(), dis.begin() + n + 1, 1e9);
    deque<int> q;
    q.push_back(st), dis[st] = 0;
    while (!q.empty()) {
        int cur = q.front();
        q.pop_front(), inq[cur] = false;
        for (auto& to : G[cur]) {
            if (dis[to] > dis[cur] + 1) {
                dis[to] = dis[cur] + 1;
                onChain[to] = outChain[to] = 0;
                if (id[to] && id[cur] && id[cur] - 1 == id[to]) onChain[to] = 1;
                else outChain[to] = 1;
                if (!inq[to]) { //slf
                    if (q.empty() || dis[to] < dis[q.front()]) q.push_front(to);
                    else q.push_back(to);
                    inq[to] = true;
                }
            } else if (dis[to] == dis[cur] + 1) { //多条最短路
                if (id[to] && id[cur] && id[cur] - 1 == id[to]) onChain[to] = 1;
                else outChain[to] = 1; //不在链上
            }
        }
    }
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> m;
    for (int i = 1, u, v; i <= m; i++) cin >> u >> v, G[v].push_back(u);
    cin >> c;
    for (int i = 1; i <= c; i++) cin >> chain[i], id[chain[i]] = i;
    spfa(chain[c]); //处理最短路
    for (int i = c - 1; i >= 1; i--) //处理工作路径到终点的距离
        chainDis[chain[i]] = chainDis[chain[i + 1]] + 1;
    int min = 0, max = 0;
    for (int i = 1; i < c; i++) {
        if (chainDis[chain[i]] > dis[chain[i]]) {
            if (!onChain[chain[i]]) min++;
        } else break;
    }
    for (int i = 1; i < c; i++) {
        if (chainDis[chain[i]] > dis[chain[i]]) {
            if (outChain[chain[i]]) max++;
        } else {
            if (outChain[chain[i]]) max++; //有多条最短路
            else break;
        }
    }
    cout << min << " " << max << endl;
    return 0;
}
```

# One Occurrence
  - [题目链接](https://www.luogu.com.cn/problem/CF1000F)
  - 数据结构/线段树/可持久化线段树
  - 数据结构/莫队/栈

<!-- more -->
# Description
多次询问区间中只出现一次的任意一个数。
# Solution
可持久化线段树做法：
对下标建立可持久化线段树。令 $pre_{a_i}$ 表示 $a_i$ 出现的上一个位置，初始值为 0。如果 $a_i$ 出现过，则将 $pre_{a_i}$ 位置的值修改为 INF。如果一个数在 $[l, r]$ 只出现了一次，那么在该区间中一定有 $pre < l$。对 $root_r$ 进行区间 $[l, r]$ 查询返回下标即可。
莫队 + 栈 (惰性删除)：
维护每个数出现次数 $cnt_i$， 如果一个数出现次数等于 1，则将其进栈。如果一个数的出现次数由 1 变为 0 或 变为 2 时，令 $deleted_i ++$，表示删除一次，不直接在栈中操作。查询时，如果栈顶的数 i 的 $deleted_i > 0$ 说明要出栈，一直弹到 $deleted_i = 0$ 为止。
# Code
```cpp One Occurrence (Persistent Segment Tree)
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 5e5 + 5;

template<typename T>
inline void read(T& x, T f = 1, char ch = getchar()) {
    x = 0;
    while (!isdigit(ch)) f = (ch == '-') ? -1 : 1, ch = getchar();
    while (isdigit(ch)) x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct SegTree {
    SegTree * lson, *rson;
    int min = 1e9;
} *root[MAXN], tree[MAXN * 60];
int n, m, pre[MAXN], arr[MAXN];

inline SegTree* newNode (SegTree*& root) {
    static int tot;
    return root = &tree[tot++];
}

inline void build(SegTree* root, int L, int R) {
    if (L == R) return;
    int mid = (L + R) >> 1;
    build(newNode(root->lson), L, mid);
    build(newNode(root->rson), mid + 1, R);
}

inline void modify (SegTree* pre, SegTree*& root, int L, int R, int pos, int val) {
    root = newNode(root), *root = *pre;
    if (L == pos && R == pos) {
        root->min = val;
        return;
    }
    int mid = (L + R) >> 1;
    if (pos <= mid) modify(pre->lson, root->lson, L, mid, pos, val);
    else modify(pre->rson, root->rson, mid + 1, R, pos, val);
    root->min = min(root->lson->min, root->rson->min);
}

inline int query(SegTree* root, int L, int R, int qL, int qR) {
    if (L > qR || R < qL || root->min >= qL) return 0;
    if (L == R) return L;
    int mid = (L + R) >> 1;
    int tmp = query(root->lson, L, mid, qL, qR);
    if (!tmp) return query(root->rson, mid + 1, R, qL, qR);
    return tmp;
}

int main() {
    read(n);
    build(newNode(root[0]), 1, n);
    for (int i = 1; i <= n; i++) {
        read(arr[i]);
        root[i] = root[i - 1];
        if (pre[arr[i]]) modify(root[i], root[i], 1, n, pre[arr[i]], 1e9);
        modify(root[i], root[i], 1, n, i, pre[arr[i]]);
        pre[arr[i]] = i;
    }
    read(m);
    while (m--) {
        int l, r;
        read(l), read(r);
        printf("%d\n", arr[query(root[r], 1, n, l, r)]);
    }
    return 0;
}
```

# Rip Van Winkle's Code
  - [题目链接](https://www.luogu.com.cn/problem/UVA12436)
  - 线段树

<!-- more -->
# Description
有一个序列初始值全为零，现有一下四种操作：
  - A l r 将区间 $[l, r]$ 加上等差数列 $1, 2, ..., r - l + 1$
  - B l r 将区间 $[l, r]$ 加上等差数列 $r - l + 1, r - l, ..., 1$
  - C l r x 将区间 $[l, r]$ 赋值 $x$
  - S l r 求区间 $[l, r]$ 的和

# Solution
难点在于区间加等差数列。
用 $Lval$ 表示表示该区间增加的等差数列的首项标记，$tag2$ 表示表示该区间增加的等差数列的公差标记。因为一个加上等差数列的区间依旧是一个等差数列区间，于是两个标记可以累加。左右儿子增加的 $sum$ 由父亲节点的 $Lval$ 和 $tag2$ 推出。
注意：$Lval$ 和 $tag2$ 都为 0 时标记不用下放；当有区间赋值标记时，等差数列标记无效，赋为 0。
# Code
```cpp Rip Van Winkle's Code
#include <bits/stdc++.h>
#define int long long

using namespace std;

constexpr int MAXN = 3e5 + 5;

template <typename T>
inline void read(T& x, T f = 1, char ch = getchar()) {
    x = 0;
    while (!isdigit(ch)) f = (ch == '-') ? -1 : 1, ch = getchar();
    while (isdigit(ch)) x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

struct SegTree {
    SegTree *lson, *rson;
    int l, r;
    int sum, Lval; // sum为区间和，Lval为增加的等差数列首项标记
    int tag1 = 1e18, tag2;  // tag1为区间赋值标记，tag2为公差标记
} * root, tree[MAXN << 1];

inline SegTree* newNode(SegTree*& root) {
    static int tot;
    return root = &tree[tot++];
}

inline void update(SegTree* root) {
    root->sum = root->lson->sum + root->rson->sum;
}

inline int size(SegTree* root) { return root->r - root->l + 1; }
/*等差数列求和 @param Lval 首项 @param d 公差 @param len 项数*/
inline int sum(int Lval, int d, int len) {
    return Lval * len + d * len * (len - 1) / 2;
}

inline void build(SegTree* root, int l, int r) {
    root->l = l, root->r = r;
    if (l == r) return;
    int mid = (l + r) >> 1;
    build(newNode(root->lson), l, mid);
    build(newNode(root->rson), mid + 1, r);
}

inline void pushTag(SegTree* root) {
    if (root->tag1 != 1e18) {  //区间修改
        root->lson->tag1 = root->tag1, root->rson->tag1 = root->tag1;
        //区间修改后首项 公差为 0
        root->lson->Lval = root->rson->Lval = 0;
        root->lson->tag2 = root->rson->tag2 = 0;

        root->lson->sum = root->tag1 * size(root->lson);
        root->rson->sum = root->tag1 * size(root->rson);
        root->tag1 = 1e18;
    }
    if (root->tag2 || root->Lval) {  //区间等差数列
        root->lson->tag2 += root->tag2, root->rson->tag2 += root->tag2;

        root->lson->Lval += root->Lval;
        root->rson->Lval += root->Lval + root->tag2 * size(root->lson);
        //注意是从父亲root->Lval累加下来 新增的等差数列求和
        root->lson->sum += sum(root->Lval, root->tag2, size(root->lson));
        root->rson->sum += sum(root->Lval + root->tag2 * size(root->lson),
                               root->tag2, size(root->rson));
        root->tag2 = root->Lval = 0;  //两个都要清零
    }
}

inline void modify(SegTree* root, int l, int r, int val, int type) {
    if (l <= root->l && root->r <= r) {
        if (type == 1) {  //区间赋值
            root->sum = val * size(root);
            root->tag1 = val;
            root->Lval = root->tag2 = 0;  //!
        } else if (type == 2) {           //区间增加等差数列 公差 1
            root->Lval += root->l - l + val;
            root->tag2++;
            root->sum += sum(root->l - l + val, 1, size(root));
        } else {  //区间增加等差数列 公差 -1
            root->Lval += l - root->l + val;
            root->tag2--;
            root->sum += sum(l - root->l + val, -1, size(root));
        }
        return;
    }
    pushTag(root);
    int mid = (root->l + root->r) >> 1;
    if (l <= mid) modify(root->lson, l, r, val, type);
    if (r > mid) modify(root->rson, l, r, val, type);
    update(root);
}

inline int query(SegTree* root, int l, int r) {  //查询求和
    if (l <= root->l && root->r <= r) return root->sum;
    pushTag(root);
    int mid = (root->l + root->r) >> 1, res = 0;
    if (l <= mid) res += query(root->lson, l, r);
    if (r > mid) res += query(root->rson, l, r);
    return res;
}

signed main() {
    int n;
    read(n);
    build(newNode(root), 1, 250000);
    char opt[2];
    for (int i = 1, l, r, x; i <= n; i++) {
        scanf("%s", opt), read(l), read(r);
        if (opt[0] == 'A') modify(root, l, r, 1, 2);
        else if (opt[0] == 'B') modify(root, l, r, r - l + 1, 3);
        else if (opt[0] == 'C') read(x), modify(root, l, r, x, 1);
        else printf("%lld\n", query(root, l, r));
    }
    return 0;
}
```

