## HEOI2015 小Z的房间
### Description
[题目链接](https://www.luogu.com.cn/problem/P4111)
### Solution
模板题，不过注意不要建重边。
### Code
```cpp 小Z的房间
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 2000;
constexpr int MOD = 1e9;

int n, m, tot, mp[MAXN][MAXN];

LL G[MAXN][MAXN];
inline LL Gauss() {
    LL ans = 1;
    for (int i = 1; i < tot; i++) {
        for (int j = i + 1; j < tot; j++)
            while (G[j][i]) {
                LL t = G[i][i] / G[j][i];
                for (int k = i; k < tot; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                ans = -ans;
            }
        ans = ans * G[i][i] % MOD;
    }
    return (ans + MOD) % MOD;
}

inline void add(int u, int v) {
    if (u > v) return;
    G[u][u]++, G[v][v]++;
    G[u][v]--, G[v][u]--;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> m;
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++) {
            char ch;
            cin >> ch;
            if (ch == '.') mp[i][j] = ++tot;
        }
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++) {
            int u = mp[i][j], v;
            if (!u) continue;
            if (v = mp[i - 1][j]) add(u, v);
            if (v = mp[i + 1][j]) add(u, v);
            if (v = mp[i][j - 1]) add(u, v);
            if (v = mp[i][j + 1]) add(u, v);
        }
    cout << Gauss() << endl;
    return 0;
}
```

## B SHOI2016 黑暗前的幻想乡
### Description
[题目链接](https://www.luogu.com.cn/problem/P4336)
### Solution
矩阵树+容斥+状态压缩。
令 $P_i$ 表示事件: 第 $i$ 个公司没有参与修建。由容斥原理有 $|\overline{P_1} \cap \overline{P_2} \cap ...\cap \overline{P_{n-k}}|= N-\sum\limits_{1<=i<={n-k}}|P_i|+\sum\limits_{1<=i<j<={n-k}}|P_i\cap P_j|$ $-\sum\limits_{1<=i<j<q<={n-k}}|P_i\cap P_j\cap P_q|+...+(-1)^{n-k}|P_1\cap P_2 \cap ...\cap P_{n-k}|$。压缩公司的参与状态即可。
### Code
```cpp 黑暗前的幻想乡
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MOD = 1e9 + 7;

int n, m, tot;
vector<pair<int, int>> vec[20];

LL G[20][20];
inline LL Gauss() {
    LL ans = 1;
    for (int i = 1; i < n; i++) {
        for (int j = i + 1; j < n; j++)
            while (G[j][i]) {
                LL t = G[i][i] / G[j][i];
                for (int k = i; k < n; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                ans = -ans;
            }
        ans = ans * G[i][i] % MOD;
    }
    return (ans + MOD) % MOD;
}

inline void add(int u, int v) {
    G[u][u]++, G[v][v]++;
    G[u][v]--, G[v][u]--;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n;
    for (int i = 0, cnt; i < n - 1; i++) {
        cin >> cnt;
        for (int j = 1, u, v; j <= cnt; j++) {
            cin >> u >> v;
            vec[i].emplace_back(u, v);
        }
    }
    LL ans = 0;
    for (int st = 0; st < (1 << (n - 1)); st++) {
        int cnt = 0;
        memset(G, 0, sizeof(G));
        for (int i = 0; i < n - 1; i++)
            if (st & (1 << i)) {
                for (auto& e : vec[i])
                    add(e.first, e.second);
                cnt++;
            }
        if ((n - cnt - 1) & 1) ans = (ans - Gauss()) % MOD;
        else ans = (ans + Gauss()) % MOD;
    }
    cout << (ans + MOD) % MOD << endl;
    return 0;
}
```

## C SDOI2014 重建
### Description
[题目链接](https://www.luogu.com.cn/problem/P3317)
### Solution
我们已知变元矩阵树可以求 $\sum_T \prod_{e \in T} p_e$。
而本题需要求 $\sum_T \{ \prod_{e \in T} p_e \prod_{e \notin T} (1 - p_e) \}$。变换可得：
$$\sum_T \{ \prod_{e \in T} p_e \prod_{e \notin T} (1 - p_e) \}$$
$$= \sum_T \{ \prod_{e \in T} p_e \frac{\prod_e (1 - p_e)}{\prod_{e \in T} (1-p_e)} \}$$
$$= \prod_e (1 - p_e) (\sum_T \prod_{e \in T} \frac{p_e}{1-p_e})$$
然后以 $\frac{p_e}{1 - p_e}$ 为边权使用变元矩阵树求边权积的和即可。
### Code
```cpp 重建
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

int n;
double ans(1), eps = 1e-8;

double G[55][55], p[55][55];
inline double Gauss() {
    double ans = 1;
    for (int i = 1; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (fabs(G[i][i]) < eps) swap(G[i], G[j]), ans = -ans;
            else break;
        }
        for (int j = i + 1; j < n; j++) {
            if (fabs(G[j][i]) < eps) continue;
            double tmp = G[j][i] / G[i][i];
            for (int k = i; k < n; k++)
                G[j][k] -= tmp * G[i][k];
        }
        ans = ans * G[i][i];
    }
    return ans;
}

inline void add(int u, int v, double val) {
    G[u][u] += val, G[v][v] += val;
    G[u][v] -= val, G[v][u] -= val;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cout << setprecision(4) << fixed;
    cin >> n;
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= n; j++) {
            cin >> p[i][j];
            if (i >= j) continue;
            double tmp = fabs(1.0 - p[i][j]) < eps ? eps : fabs(1.0 - p[i][j]);
            ans *= tmp, p[i][j] /= tmp;
            add(i, j, p[i][j]);
        }
    cout << ans * fabs(Gauss()) << endl;
    return 0;
}
```

## D HDU多校 Expectation
### Description
[题目链接](http://acm.hdu.edu.cn/showproblem.php?pid=6836)
求生成树边权按位与的期望。
### Solution
期望 = 按位与的和 / 总生成树个数。生成树个数可以用矩阵树求出。对于按位与，考虑每一位，如果生成树边权的第 $bit$ 位全为 1，则 $bit$ 位的按位与为1，否则为0。相当于0, 1的乘积。于是可对每一位跑变元矩阵树，最后按位累加即为按位与的和。
### Code Expectation
```cpp
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 300;
constexpr LL INF = 1e16;
constexpr LL MOD = 998244353;

int t, n, m;

inline LL qpow(LL a, LL b) {
    LL res = 1;
    while (b) {
        if (b & 1) res = res * a % MOD;
        a = a * a % MOD;
        b >>= 1;
    }
    return res;
}

LL K[110][110], K2[32][110][110];
LL gauss(int n) {  //求矩阵K的n-1阶顺序主子式
    LL res = 1;
    for (int i = 1; i <= n - 1; i++) {  //枚举主对角线上第i个元素
        for (int j = i + 1; j <= n - 1; j++) {  //枚举剩下的行
            while (K[j][i]) {                   //辗转相除
                int t = K[i][i] / K[j][i];
                for (int k = i; k <= n - 1; k++)  //转为倒三角
                    K[i][k] = (K[i][k] - t * K[j][k] + MOD) % MOD;
                swap(K[i], K[j]);  //交换i、j两行
                res = -res;        //取负
            }
        }
        res = (res * K[i][i]) % MOD;
    }
    return (res + MOD) % MOD;
}

LL gauss2(int n, int bit) {  //求矩阵K的n-1阶顺序主子式
    LL res = 1;
    for (int i = 1; i <= n - 1; i++) {  //枚举主对角线上第i个元素
        for (int j = i + 1; j <= n - 1; j++) {  //枚举剩下的行
            while (K2[bit][j][i]) {                   //辗转相除
                int t = K2[bit][i][i] / K2[bit][j][i];
                for (int k = i; k <= n - 1; k++)  //转为倒三角
                    K2[bit][i][k] = (K2[bit][i][k] - t * K2[bit][j][k] + MOD) % MOD;
                swap(K2[bit][i],K2[bit][j]);  //交换i、j两行
                res = -res;        //取负
            }
        }
        res = (res * K2[bit][i][i]) % MOD;
    }
    return (res + MOD) % MOD;
}

int main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> t;
    while (t--) {
        memset(K, 0, sizeof(K));
        memset(K2, 0, sizeof(K2));
        cin >> n >> m;
        LL ans = 0;
        for (int i = 1, u, v, w; i <= m; i++) {
            cin >> u >> v >> w;
            for (int j = 0; j < 31; j++) {
                int tmp = (w & (1 << j));
                if (tmp) {
                    K2[j][u][u]++, K2[j][v][v]++;
                    K2[j][u][v]--, K2[j][v][u]--;
                }
            }
            K[u][u]++, K[v][v]++;
            K[u][v]--, K[v][u]--;
        }
        LL fenMu = gauss(n);
        for (int i = 0; i < 31; i++) {
            ans = (ans + ((gauss2(n, i) << i) % MOD)) % MOD;
        }
        cout << ans * qpow(fenMu, MOD - 2) % MOD << "\n";
    }
    return 0;
}
```

## E 最小生成树计数
### Description
[题目链接](https://www.luogu.com.cn/problem/P4208)
### Solution
最小生成树有一个性质是，同一边权的边的数目是相同的。考虑先随意生成一个最小生成树，然后对生成树上的每个权值计算贡献 (相同边权只计算一次)。
具体来说，就是枚举最小生成树上的边，将其删除 (设边权为 $w_i$，相同边权只删除一次)，然后得到若干连通块 (缩成一个点)。再用所有边权为 $w_i$ 的边把连通块连接起来，对这些连通块的生成树计数，最后乘法原理得到最终答案。
### Code
```cpp 最小生成树计数
#include <bits/stdc++.h>

using namespace std;
using LL = long long;

constexpr int MAXN = 105;
constexpr int MOD = 31011;

int n, m, ans = 1, fa[MAXN], vis[MAXN], belong[MAXN];
vector<pair<int, pair<int, int>>> vec, eTree;

inline int find(int x) { return fa[x] == x ? x : fa[x] = find(fa[x]); }

inline void Union(int a, int b) {
    int r1 = find(a), r2 = find(b);
    if (r1 != r2) fa[r1] = r2;
}

inline void kruskal(int cnt = 0) {
    for (int i = 1; i <= n; i++) fa[i] = i;
    sort(vec.begin(), vec.end());
    for (auto& e : vec) {
        int w = e.first, u = e.second.first, v = e.second.second;
        if (find(u) != find(v)) {
            cnt++;
            Union(u, v);
            eTree.push_back(make_pair(w, make_pair(u, v)));
        }
        if (cnt == n - 1) break;
    }
}

int G[MAXN][MAXN];
inline LL Gauss(int n) {
    LL ans = 1;
    for (int i = 1; i < n; i++) {
        for (int j = i + 1; j < n; j++)
            while (G[j][i]) {
                LL t = G[i][i] / G[j][i];
                for (int k = i; k < n; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                ans = -ans;
            }
        ans = ans * G[i][i] % MOD;
    }
    return (ans + MOD) % MOD;
}

inline void add(int u, int v) { G[u][u]++, G[v][v]++, G[u][v]--, G[v][u]--; }

inline int calc(int res = 1) {
    for (int i = 0; i < eTree.size(); i++) {
        if (i && eTree[i - 1].first == eTree[i].first) continue;
        int cnt = 0;
        memset(G, 0, sizeof(G)), memset(vis, 0, sizeof(vis));
        for (int j = 1; j <= n; j++) fa[j] = j;
        for (auto& e : eTree) { //生成树上权值不为eTree[i]的边，求出联通块
            int w = e.first, u = e.second.first, v = e.second.second;
            if (w == eTree[i].first) continue;
            Union(u, v);
        }
        for (int j = 1; j <= n; j++) {//处理连通块数目 方便后续生成树Gauss计数
            if (!vis[find(j)]) vis[find(j)] = ++cnt;
            belong[j] = vis[find(j)];
        }
        for (auto& e : vec) { //所有边，将连通块相连
            int w = e.first, u = e.second.first, v = e.second.second;
            if (w != eTree[i].first) continue;
            add(belong[u], belong[v]); //加边
        }
        res = res * Gauss(cnt) % MOD;
    }
    return res;
}

int main () {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> m;
    for (int i = 1, u, v, w; i <= m; i++) {
        cin >> u >> v >> w;
        vec.push_back(make_pair(w, make_pair(u, v)));
    }
    kruskal();
    cout << calc() << endl;
    return 0;
}
```

## 有向图的有根最小生成树计数
### Description
[题目链接](https://www.luogu.com.cn/problem/P4455)
### Solution
求以 1 为根的生成树数量。
构造矩阵 $A$： $i != j$，$a_{ij}$ 表示 $i$ 到 $j$ 的有向边数的相反数；$a_{ii}$ 为 $i$ 的出度。
该矩阵去掉第 1 行，第 1 列即为以 1 为根的生成树数量。
### Code
```cpp CQOI2018 社交网络
#include <bits/stdc++.h>

using namespace std;

constexpr int MAXN = 1e3 + 3, MOD = 1e4 + 7;

int n, m, u, v;

int G[MAXN][MAXN];
inline int Gauss(int n, int res = 1) {
    for (int i = 2; i <= n; i++) {
        for (int j = i + 1; j <= n; j++) {
            while (G[j][i]) {
                int t = G[i][i] / G[j][i];
                for (int k = i; k <= n; k++)
                    G[i][k] = ((G[i][k] - t * G[j][k]) % MOD + MOD) % MOD;
                swap(G[i], G[j]);
                res = -res;
            }
        }
        res = res * G[i][i] % MOD;
    }
    return (res + MOD) % MOD;
}
/*从 u 到 v 的有向边*/
inline void add(int u, int v) { G[u][v]--, G[u][u]++; }

signed main() {
    std::ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> n >> m;
    while (m--) cin >> u >> v, add(u, v);
    cout << Gauss(n) << endl;
    return 0;
}
```

