下面的题可用用 Trie 树实现，主要分为4个等级。

# Level 1
Trie 树基础
## A 于是他错误的点名开始了
### Description
[P2580 于是他错误的点名开始了](https://www.luogu.com.cn/problem/P2580)
### Solution
首先把给出的 $n$ 个字符串插入 $trie$ 树中。之后询问时，如果给出的字符串在 $trie$ 树中不存在，否则在字符串末尾对应节点打上标记，如果这个点之前已经被打过标记，说明这个字符串在之前已经被询问过了。
### Code
```cpp 于是他错误的点名开始了
#include <bits/stdc++.h>

using namespace std;

struct trie {
    trie *son[26];
    trie() {
        for (int i = 0; i < 26; i++) son[i] = NULL;
        tag = 0;
    }
    bool tag;
};

trie *root = new trie;
int n, m;
string s;

void insert(const string &s) {
    trie *cur = root;
    for (int i = 0; i < s.size(); i++) {
        int temp = s[i] - 'a';
        if (cur->son[temp] == NULL) cur->son[temp] = new trie;
        cur = cur->son[temp];
    }
}

int search(const string &s) {
    trie *cur = root;
    for (int i = 0; i < s.size(); i++) {
        int temp = s[i] - 'a';
        if (cur->son[temp] == NULL) return 0;
        cur = cur->son[temp];
        if (i == s.size() - 1) {
            if (!cur->tag)
                return cur->tag = 1, 1;
            else
                return 2;
        }
    }
}

int main() {
    cin >> n;
    while (n--) cin >> s, insert(s);
    cin >> m;
    while (m--) {
        cin >> s;
        int now = search(s);
        if (now == 0)
            cout << "WRONG" << endl;
        else if (now == 1)
            cout << "OK" << endl;
        else
            cout << "REPEAT" << endl;
    }
    return 0;
}
```
## B PHONELST Phone List
### Description
[SP4033 PHONELST - Phone List](https://www.luogu.com.cn/problem/SP4033)
### Solution
考虑两种情况，若当前串是前面已插入的串中某一个串的前缀，那么它在 $ trie$ 上对应的最后一个节点之前应该被访问过；若前面已插入的串中存在当前串的前缀，那么在插入当前串时，一定会访问到 $trie$ 上的某个节点，且该节点对应之前某个串的结尾。因此只需要打两个标记，一个记录节点是否被访问过，一个记录节点是否对应某个串的结尾，这两个标记边插入边更新即可。
### Code
```cpp
#include <bits/stdc++.h>

using namespace std;

struct trie {
    trie *son[10];
    trie() {
        for (int i = 0; i < 10; i++) son[i] = NULL;
        visTag = isEnd = 0;
    }
    bool visTag, isEnd;
} * root;

int n, T;
bool ans;
string s;

void insert(const string &s) {
    trie *cur = root;
    for (int i = 0; i < s.size(); i++) {
        int temp = s[i] - '0';
        if (cur->son[temp] == NULL) cur->son[temp] = new trie;
        cur = cur->son[temp];
        if (cur->isEnd) {
            ans = 0;
            break;
        }
        if (i == s.size() - 1) {
            cur->isEnd = 1;
            if (cur->visTag) ans = 0;
        }
        cur->visTag = 1;
    }
}

void trie_delete(trie *cur) {
    for (int i = 0; i < 10; i++)
        if (cur->son[i]) trie_delete(cur->son[i]);
    delete cur;
}

int main() {
    cin >> T;
    while (T--) {
        root = new trie;
        ans = 1;
        cin >> n;
        for (int i = 1; i <= n; i++) cin >> s, insert(s);
        puts(ans ? "YES" : "NO");
        trie_delete(root);
    }
    return 0;
}
```

# Level 2
$01Trie$ 贪心计算最大异或值
## A Xor Sum
### Description
[HDU 4825 - Xor Sum](https://www.luogu.com.cn/problem/U109895)
### Solution
首先将集合中的每个数化为二进制形式，分别从高位到低位依次插入 $trie$ 树中。对于任意给定的数，要使异或结果最大，那么异或结果的每一位尽可能是1，也就是说给定的数，和使异或结果最大的数，在每一位的值尽可能相反。每次贪心的选取，在 $trie$ 树上走互补的链即可。单次查询的复杂度为
$log_2(S)$。

注：用指针版 $trie$ 树直接 $new$ 的话常数较大，会被卡。可以自己手写$newNode$ 函数，或者改用数组版。
### Code
```cpp Xor Sum
#include <bits/stdc++.h>

using namespace std;

typedef long long ll;
const int BIT = 32;

struct trie {
    int son[2];
    trie() { son[0] = son[1] = -1; }
} trie[16000000];

int root = 0;
int n, m;

ll read() {
    char ch = getchar();
    ll x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(ll val) {
    static int tot;
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
    }
}

void query(ll val) {
    int cur = root;
    ll ans = 0;
    for (int i = BIT; ~i; i--) {
        ll now = (val >> i) & 1;
        if (trie[cur].son[now ^ 1] != -1)
            ans |= (now ^ 1) << i, cur = trie[cur].son[now ^ 1];
        else
            ans |= now << i, cur = trie[cur].son[now];
    }
    printf("%lld\n", ans);
}

int main() {
    n = read(), m = read();
    for (int i = 1; i <= n; i++) insert(read());
    for (int i = 1; i <= m; i++) query(read());
    return 0;
}
```
## B Chip Factory
### Description
[HDU 5536 - Chip Factory](https://www.luogu.com.cn/problem/U109897)
### Solution
做法和上一道类似。先把给出的 $n$ 个数插入 $trie$ 树，然后枚举 $i$ 和 $j$，把 $s[i] + s[j]$ 放到 $trie$ 树上贪心地查询即可,单次查询复杂度为 $log_2(s)$。需要注意的是，题目要求 $i,j,k$ 互不相同，因此选了 $s[i],s[j]$ 后，应将它们从 $trie$ 树上删除。具体的，每个节点记一个 $cnt$， 删除的时候让 $cnt-1$ ，查询时如果该节点 $cnt$ 为 0 说明已被删除，则不能选这个节点。单次查询结束后再把  $s[i],s[j]$ 插入 $trie$ 树即可，这样不影响之后的查询。
### Code
```cpp Chip Factory
#include <bits/stdc++.h>

using namespace std;

int n, a[1001], mx = 0;
const int BIT = 31;

struct trie {
    int son[2];
    int cnt;
    trie() {
        son[0] = son[1] = -1;
        cnt = 0;
    }
} trie[1001 * (BIT + 1)];
int root = 0;

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(int val) {
    static int tot;
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
        trie[cur].cnt++;
    }
}

void trie_delete(int val) {
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        cur = trie[cur].son[now];
        trie[cur].cnt--;
    }
}

void trie_add(int val) {
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        cur = trie[cur].son[now];
        trie[cur].cnt++;
    }
}

void query(int val, int x, int y) {
    trie_delete(a[x]), trie_delete(a[y]);
    int cur = root;
    int ans = 0;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now ^ 1] != -1 && trie[trie[cur].son[now ^ 1]].cnt)
            ans |= 1 << i, cur = trie[cur].son[now ^ 1];
        else if (trie[trie[cur].son[now]].cnt)
            cur = trie[cur].son[now];
        else
            return;
    }
    trie_add(a[x]), trie_add(a[y]);
    mx = max(mx, ans);
}

int main() {
    n = read();
    for (int i = 1; i <= n; i++) a[i] = read();
    for (int i = 1; i <= n; i++) insert(a[i]);
    for (int i = 1; i <= n; i++)
        for (int j = i + 1; j <= n; j++) query(a[i] + a[j], i, j);
    cout << mx;
    return 0;
}
```
## C Nikitosh and xor
### Description
[Codechef REBXOR - Nikitosh and xor](https://www.luogu.com.cn/problem/U109923)
### Solution
记 $preMx[i]$ 表示从 $1$ 到 $i$ 的最大连续片段异或和，$posMx[i]$ 表示从 $i$ 到 $n$ 的最大连续片段异或和。显然，答案为 $\max\limits_{0<i<n}(preMx[i]+posMx[i+1])$。接下来只需要预处理出 $preMx[i]$ 和 $posMx[i]$ 即可。
记 $preXor[i]$ 表示 $1$ 到 $i$ 的前缀异或和。同时设 $preXor[k](0<=k <i)$ 已计算出，并且已被插入 $trie$ 中, 那么根据异或运算的性质，有 $preMx[i]=\max\limits_{0<=k<i}(preMx[i-1], preXor[i]⊕preXor[k])$，而$\max\limits_{0<=k<i}(preXor[i]⊕preXor[k])$ 可以在 $trie$ 树上，在 $log_2(a)$的时间内贪心地求出。同样的，容易求出 $posMx[i]$。
### Code
```cpp Nikitosh and xor
#include <bits/stdc++.h>

using namespace std;

typedef long long ll;
const int BIT = 31;
const int maxn = 400005;
int n, a[maxn], tot;
ll preXor = 0, posXor = 0, preMx[maxn], posMx[maxn];
ll ans = 0;

struct trie {
    int son[2];
    trie() { son[0] = son[1] = -1; }
} trie[maxn * BIT * 2];
int root;

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(ll val) {
    int cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
    }
}

ll query(ll val) {
    int cur = root;
    ll ans = 0;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (trie[cur].son[now ^ 1] != -1)
            ans |= 1ll << i, cur = trie[cur].son[now ^ 1];
        else
            cur = trie[cur].son[now];
    }
    return ans;
}

int main() {
    n = read();
    for (int i = 1; i <= n; i++) a[i] = read();

    insert(0);
    for (int i = 1; i <= n; i++) {
        preXor ^= a[i];
        insert(preXor);
        preMx[i] = max(preMx[i - 1], query(preXor));
    }
    for (int i = 0; i <= tot; i++) trie[i].son[0] = trie[i].son[1] = -1;
    tot = 0;

    insert(0);
    for (int i = n; i >= 1; i--) {
        posXor ^= a[i];
        insert(posXor);
        posMx[i] = max(posMx[i + 1], query(posXor));
    }
    for (int i = 1; i <= n - 1; i++) ans = max(ans, posMx[i + 1] + preMx[i]);
    cout << ans;
    return 0;
}
```
## D 最长异或路径
### Descritiption
[P4551 最长异或路径](https://www.luogu.com.cn/problem/P4551)
### Solution
首先 $dfs$ 求出每个点 $i$ 到根节点路径上的异或和，记为 Xor[i]。显然，答案为 $\max\limits_{1<=u<=n}( \max\limits_{1<=v<=n}(Xor[u]⊕Xor[v]))$。对于任意节点 $u$，它和其它节点的最大异或值可以在 $trie$ 树上在 $log_2(w)$ 的时间内贪心地求得。

### Code
```cpp 最长异或路径
#include <bits/stdc++.h>

using namespace std;

const int maxn = 100005;
const int BIT = 30;

int p[maxn], XOR[maxn];
int n, u, v, w, ans;
bool vis[maxn];

struct trie {
    trie *son[2];
    int val;
    trie() { son[0] = son[1] = NULL; }
} * root;

struct edge {
    int nxt, to, val;
} e[maxn * 2];

template <class T>
void read(T &x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

void add(int from, int to, int val) {
    static int t;
    e[t].to = to, e[t].val = val, e[t].nxt = p[from], p[from] = t++;
}

void dfs(int now, int val) {
    XOR[now] = val, vis[now] = 1;
    for (int i = p[now]; ~i; i = e[i].nxt) {
        int to = e[i].to;
        if (!vis[to]) dfs(to, val ^ e[i].val);
    }
}

void insert(int val) {
    trie *cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
    }
}

int query(int val) {
    trie *cur = root;
    int ans = 0;
    for (int i = BIT; ~i; i--) {
        int now = (val >> i) & 1;
        if (cur->son[now ^ 1] != NULL)
            ans |= 1 << i, cur = cur->son[now ^ 1];
        else
            cur = cur->son[now];
    }
    return ans;
}

int main() {
    memset(p, -1, sizeof(p));
    read(n);
    for (int i = 1; i <= n - 1; i++) {
        read(u), read(v), read(w);
        add(u, v, w), add(v, u, w);
    }
    dfs(1, 0);
    root = new trie;
    for (int i = 1; i <= n; i++) insert(XOR[i]);
    for (int i = 1; i <= n; i++) ans = max(ans, query(XOR[i]));
    cout << ans;
    return 0;
}
```

