## A USACO08DEC Secret Message G
### Descritption
[P2922 USACO08DEC Secret Message G](https://www.luogu.com.cn/problem/P2922)

### Solution
首先按题意建好 $trie$ 树。对于一个暗号，需要求出有多少条信息是它的前缀，以及它是多少条信息的前缀。用 $cntEnd$ 表示有多少条信息以该节点为结尾，$sum$ 表示该节点对应信息是多少条信息的前缀。每次查询可以求出在最后一位之前该暗号前缀的个数，在最后一个节点通过 $sum$ 可以得到这个暗号是多少条信息的前缀，加起来去个重即可。
### Code
```cpp Secret Message G
#include <bits/stdc++.h>

using namespace std;

int m, n, k;
bool v;

struct trie {
    trie* son[2];
    int cntEnd, sum;
    trie() {
        son[1] = son[0] = NULL;
        cntEnd = sum = 0;
    }
} * root;

template <class T>
void read(T& x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

void insert(vector<bool>& bin) {
    trie* cur = root;
    for (int i = 0; i < bin.size(); i++) {
        int now = bin[i];
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        cur->sum++;
    }
    cur->cntEnd++;
}

int query(vector<bool>& bin) {
    trie* cur = root;
    int ans = 0;
    for (int i = 0; i < bin.size(); i++) {
        int now = bin[i];
        if (cur->son[now] == NULL) return ans;
        cur = cur->son[now];
        ans += cur->cntEnd;
    }
    ans += cur->sum - cur->cntEnd;
    return ans;
}

int main() {
    read(m), read(n);
    root = new trie;
    for (int i = 1; i <= m; i++) {
        read(k);
        vector<bool> bin;
        for (int i = 1; i <= k; i++) read(v), bin.push_back(v);
        insert(bin);
    }
    for (int i = 1; i <= n; i++) {
        read(k);
        vector<bool> bin;
        for (int i = 1; i <= k; i++) read(v), bin.push_back(v);
        cout << query(bin) << endl;
    }
    return 0;
}
```
## B IOI2008 Type Printer 打印机
### Descritption
[P4683 IOI2008 Type Printer 打印机](https://www.luogu.com.cn/problem/P4683)

### Solution
容易发现，所有字符串都要打印，除了最后一个外都要删除。要使按键次数最少，最后打印的字符串必须最长。对最长的字符串在 $trie$ 树上打个标记，$dfs$ 时把有标记的节点放在最后搜索就行了。

### Code
```cpp Type Printer
#include <bits/stdc++.h>

using namespace std;

int n;
char s[21];
vector<char> ans;
struct trie {
    int son[26];
    bool isEnd, tag;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = -1;
        isEnd = tag = 0;
    }
} trie[25000 * 20];
int root, tot;

void insert(const string& s) {
    int cur = root;
    for (int i = 0; i < s.size(); i++) {
        int now = s[i] - 'a';
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
    }
    trie[cur].isEnd = 1;
}

void addTag(const string& s) {
    int cur = root;
    for (int i = 0; i < s.size(); i++) {
        cur = trie[cur].son[s[i] - 'a'];
        trie[cur].tag = 1;
    }
}

void dfs(int now) {
    int last = -1;
    for (int i = 0; i < 26; i++) {
        if (trie[now].son[i] != -1) {
            if (!trie[trie[now].son[i]].tag) {
                ans.push_back(i + 'a');
                if (trie[trie[now].son[i]].isEnd) ans.push_back('P');
                dfs(trie[now].son[i]);
                ans.push_back('-');
            } else
                last = i;
        }
    }
    if (last != -1) {
        ans.push_back(last + 'a');
        if (trie[trie[now].son[last]].isEnd) ans.push_back('P');
        dfs(trie[now].son[last]);
    }
}

int main() {
    scanf("%d", &n);
    int mxLen = 0;
    string lastString;
    for (int i = 1; i <= n; i++) {
        scanf("%s", s);
        if (strlen(s) > mxLen) mxLen = strlen(s), lastString = s;
        insert(s);
    }
    addTag(lastString);
    dfs(root);
    printf("%d\n", ans.size());
    for (int i = 0; i < ans.size(); i++) putchar(ans[i]), putchar('\n');
    return 0;
}
```
## C USACO12DEC First! G
### Description
[P3065 USACO12DEC First! G](https://www.luogu.com.cn/problem/P3065)

### Solution
首先建出 $trie$ 树，然后枚举每一个字符串，考察它能否排在第一个。具体的，将一个字符串放在 $trie$ 树上查询，如果途径某个点，这个点是其它串的结尾，那么该串不可能排第一；否则可以根据节点访问顺序建立关于字母优先级的图，用拓扑排序判断是否存在环，若存在环说明该字符串不能排在第一个。

### Code
```cpp USACO12DEC First! G
#include <bits/stdc++.h>

using namespace std;

const int maxn = 30005;
int n, ans;
string s[maxn];
int inDegree[26];
vector<int> v[26];
vector<int> firstId;

struct trie {
    trie* son[26];
    bool isEnd;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = NULL;
        isEnd = 0;
    }
} * root;

void insert(const string& s) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[s[i] - 'a'] == NULL) cur->son[s[i] - 'a'] = new trie;
        if (i == s.size() - 1) cur->son[s[i] - 'a']->isEnd = 1;
        cur = cur->son[s[i] - 'a'];
    }
}

bool check(const string& s) {
    for (int i = 0; i < 26; i++) {
        v[i].clear();
        inDegree[i] = 0;
    }
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        for (int j = 0; j < 26; j++)
            if (cur->son[j] != NULL && j != s[i] - 'a') {
                v[s[i] - 'a'].push_back(j);
                inDegree[j]++;
            }
        if (i != s.size() - 1 && cur->son[s[i] - 'a']->isEnd) return false;
        cur = cur->son[s[i] - 'a'];
    }
    stack<int> st;
    for (int i = 0; i < 26; i++)
        if (!inDegree[i]) st.push(i);
    while (!st.empty()) {
        int now = st.top();
        st.pop();
        for (int i = 0; i < v[now].size(); i++) {
            inDegree[v[now][i]]--;
            if (!inDegree[v[now][i]]) st.push(v[now][i]);
        }
    }
    for (int i = 0; i < 26; i++)
        if (inDegree[i]) return false;
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n;
    root = new trie;
    for (int i = 1; i <= n; i++) cin >> s[i], insert(s[i]);
    for (int i = 1; i <= n; i++)
        if (check(s[i])) firstId.push_back(i), ans++;
    cout << ans << endl;
    for (int i = 0; i < firstId.size(); i++) cout << s[firstId[i]] << endl;
    return 0;
}
```
## D CQOI2016 路由表
### Description
[P5768 CQOI2016 路由表](https://www.luogu.com.cn/problem/P5768)

### Solution
先把IP地址按题目要求转化为二进制插入 $trie$ 树，顺便对最后访问的节点记录 $inTime$ 和 $length$, 分别表示这个 $IP$ 地址被插入的时间和掩码长度。查询时，对于 $inTime$ 在 $a$ 和 $b$ 之间的 $IP$ 地址，记录对应掩码长度, 将这两个信息存入 $Vector$；对于 $inTime$ 在 $a$ 之前的节点，更新掩码长度最大值。最后对 $Vector$ 按照 $IP$ 地址按插入时间排序，然后从前到后扫一遍 $Vector$，同时更新掩码长度最大值，就可以知道该待查询的IP地址的路由表项选择发生了多少次变化。
### Code
```cpp CQOI2016 路由表
#include <bits/stdc++.h>
#define pii pair<int, int>

using namespace std;

int n, x, cntAdd, len, a, b;
char type;
struct trie {
    trie* son[2];
    int inTime, length;
    trie() {
        son[1] = son[0] = NULL;
        inTime = length = 0;
    }
} * root;

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(vector<bool>& bin, int l, int id) {
    trie* cur = root;
    for (int i = 0; i < l; i++) {
        int now = bin[i];
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        if (i == l - 1) {
            cur->inTime = id;
            cur->length = l;
        }
    }
}

void query(vector<bool>& bin, int l, int r) {
    trie* cur = root;
    int cnt = 0, mx = 0;
    vector<pii> tmp;
    for (int i = 0; i < bin.size(); i++) {
        int now = bin[i];
        if (cur->son[now] == NULL) break;
        cur = cur->son[now];
        if (cur->inTime >= l && cur->inTime <= r)
            tmp.push_back(make_pair(cur->inTime, cur->length));
        else if (cur->inTime < l)
            mx = max(mx, cur->length);
    }
    sort(tmp.begin(), tmp.end());
    for (int i = 0; i < tmp.size(); i++)
        if (tmp[i].second > mx) mx = tmp[i].second, cnt++;
    printf("%d\n", cnt);
}

int main() {
    n = read();
    root = new trie;
    for (int i = 1; i <= n; i++) {
        type = getchar();
        if (type == 'A') {
            cntAdd++;
            vector<bool> bin;
            for (int i = 1; i <= 4; i++) {
                x = read();
                for (int j = 7; ~j; j--) bin.push_back((x >> j) & 1);
            }
            len = read();
            insert(bin, len, cntAdd);
        } else {
            vector<bool> bin;
            for (int i = 1; i <= 4; i++) {
                x = read();
                for (int j = 7; ~j; j--) bin.push_back((x >> j) & 1);
            }
            a = read(), b = read();
            query(bin, a, b);
        }
    }
    return 0;
}
```
## E JSOI2009 电子字典
### Description
[P4407 JSOI2009 电子字典](https://www.luogu.com.cn/problem/P4407)

### Solution
按照题意直接暴搜即可，注意判重。
### Code
```cpp JSOI2009
#include <bits/stdc++.h>

using namespace std;

int n, m, ans, tot;
string s;
struct trie {
    trie* son[26];
    int endTag;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = NULL;
        endTag = 0;
    }
} * root;
unordered_map<int, bool> vis;

void insert(const string& s, int id) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[s[i] - 'a'] == NULL) cur->son[s[i] - 'a'] = new trie;
        cur = cur->son[s[i] - 'a'];
    }
    cur->endTag = id;
}

bool isWord(const string& s) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[s[i] - 'a'] == NULL) return false;
        cur = cur->son[s[i] - 'a'];
        if (i == s.size() - 1 && cur->endTag) return true;
    }
    return false;
}

void dfs(trie* now, int i, bool canOpt) {
    if (i == s.size()) {
        if (now->endTag && !vis[now->endTag]) ans++, vis[now->endTag] = 1;
        if (canOpt) {
            for (int k = 0; k < 26; k++)
                if (now->son[k] != NULL && now->son[k]->endTag &&
                    !vis[now->son[k]->endTag])
                    ans++, vis[now->son[k]->endTag] = 1;
        }
        return;
    }
    if (!canOpt && now->son[s[i] - 'a'] == NULL) return;
    if (now->son[s[i] - 'a'] != NULL) dfs(now->son[s[i] - 'a'], i + 1, canOpt);
    if (canOpt) {
        //增加一位
        for (int k = 0; k < 26; k++)
            if (now->son[k] != NULL) dfs(now->son[k], i, 0);
        //删除一位
        dfs(now, i + 1, 0);
        //修改一位
        for (int k = 0; k < 26; k++)
            if (now->son[k] != NULL) dfs(now->son[k], i + 1, 0);
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n >> m;
    root = new trie;
    for (int i = 1; i <= n; i++) {
        cin >> s;
        insert(s, i);
    }
    for (int i = 1; i <= m; i++) {
        vis.clear();
        cin >> s;
        if (isWord(s))
            cout << -1 << endl;
        else {
            ans = 0;
            dfs(root, 0, 1);
            cout << ans << endl;
        }
    }
    return 0;
}
```
## F AHOI2005 病毒检测
### Description
[P2536 AHOI2005 病毒检测](https://www.luogu.com.cn/problem/P2536)

### Solution
按照题意建出 $trie$ 树，然后记忆化搜索即可。本题有加强版，需要使用 AC 自动机实现通配符模糊匹配。(写完 AC 自动机博客再把链接贴上)

### Code
```cpp AHOI2005 病毒检测
#include <bits/stdc++.h>

using namespace std;

const int maxn = 505;
int n, ans, len;
char s[maxn], T[maxn * 2];
int isVirus[maxn], firstId[maxn];
int to[200];
bitset<1001> vis[maxn * maxn];

struct trie {
    trie* son[4];
    int endTag, num;
    trie() {
        for (int i = 0; i < 4; i++) son[i] = NULL;
        endTag = num = 0;
    }
} * root;

void insert(const string& s, const int& id) {
    static int tot;
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[to[s[i]]] == NULL) cur->son[to[s[i]]] = new trie;
        cur = cur->son[to[s[i]]];
        cur->num = ++tot;
    }
    if (!cur->endTag) cur->endTag = id;
    firstId[id] = cur->endTag;
}

void match(trie* now, int i) {
    if (i == len) {
        isVirus[now->endTag] = 1;
        return;
    }
    if (vis[now->num][i]) return;
    vis[now->num][i] = 1;
    if (T[i] == '*') {
        match(now, i + 1);
        for (int k = 0; k < 4; k++)
            if (now->son[k] != NULL)
                match(now->son[k], i + 1), match(now->son[k], i);
    } else if (T[i] == '?') {
        for (int k = 0; k < 4; k++)
            if (now->son[k] != NULL) match(now->son[k], i + 1);
    } else {
        if (now->son[to[T[i]]] != NULL) match(now->son[to[T[i]]], i + 1);
    }
}

int main() {
    to['A'] = 0, to['T'] = 1, to['C'] = 2, to['G'] = 3;
    scanf("%s%d", T, &n);
    len = strlen(T);
    root = new trie;
    for (int i = 1; i <= n; i++) scanf("%s", s), insert(s, i);
    for (int i = 0; i < maxn * maxn; i++) vis[i].reset();
    match(root, 0);
    for (int i = 1; i <= n; i++)
        if (isVirus[firstId[i]]) ans++;
    printf("%d\n", n - ans);
    return 0;
}
```
## G SCOI2016 背单词
### Description
[P3294 SCOI2016 背单词](https://www.luogu.com.cn/problem/P3294)

### Solution
显然，情形 $3$ 比情形 $1$ 和 $2$ 更优，因为情形 $1$ 和情形 $2$ 不管怎样都会吃大于等于 $x$ 个泡椒。只需要考虑情形 $3$，对于情形 $3$ 我们需要构建一种方案，使得$\sum(x-y)$ 最小。

首先将输入的字符串反转后插入 $trie$ 树中，这样转化为前缀方便处理。
容易发现，除了 $root$ 和 一个串最后一个字符对应节点外，其它节点对答案没有影响，我们根据这些终点节点重新构建 $trie$ 树，将多余的节点删掉。以下图为例：

设有字符串：$CA,GDA,HDA,EA,IFB$

原来的 $trie$ 树:
![](https://s2.ax1x.com/2019/10/28/K6m0Rf.png)

重新构建的 $trie$ 树:
![](https://s2.ax1x.com/2019/10/28/K6mwJP.png)

容易发现，一个节点(对应一个字符串)的贡献取决于它和它父亲被选取的时间差。可以证明，按dfs选取，且先访问size小的子树最优。

先证明按 $dfs$ 序选取一定最优，对于以同一深度的节点为根的一系列子树，在一颗中找一个叶子节点 $j$,在另一颗里找一个根节点 $i$ (当前序列中j所在的子树的根在i之前出现)。需要明确的是，只有这两种节点间才能交换顺序，否则得到序列不满足情形 $3$ 。假设 $j$ 在 $i$ 之前代价最小，尝试将 $j$ 放在 $i$ 的后面。可以发现发现 $i$ 的孩子们和 $i$ 的距离都会加 1，所以总代价会增加，而 $j$ 和 $j$ 的父亲的距离一定也会增加，所以总代价也会增加。

再证明优先选取size小的子树更优。实际上，按照dfs序，第i个选取的子树的根的贡献等于之前选取的子树的size的和，所以size小的应该放在前面。

### Code SCOI2016 背单词
```cpp
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int maxn = 510005;
int n, sz[maxn], in[maxn];
string s;
ll ans;
vector<int> v[maxn];

struct trie {
    int son[26];
    int tag;
    trie() {
        for (int i = 0; i < 26; i++) son[i] = -1;
        tag = 0;
    }
} trie[maxn];
int root, tot;

void insert(const string &s) {
    int cur = root;
    for (int i = s.size() - 1; ~i; i--) {
        int now = s[i] - 'a';
        if (trie[cur].son[now] == -1) trie[cur].son[now] = ++tot;
        cur = trie[cur].son[now];
        if (!i) trie[cur].tag = 1;
    }
}

void rebuild(int now, int pre) {
    for (int i = 0; i < 26; i++) {
        if (trie[now].son[i] != -1) {
            if (trie[trie[now].son[i]].tag) {
                v[pre].push_back(trie[now].son[i]);
                rebuild(trie[now].son[i], trie[now].son[i]);
            } else
                rebuild(trie[now].son[i], pre);
        }
    }
}

bool cmp(const int &a, const int &b) { return sz[a] < sz[b]; }
void dfs(int now) {
    sz[now] = 1;
    for (int i = 0; i < v[now].size(); i++) {
        dfs(v[now][i]);
        sz[now] += sz[v[now][i]];
    }
    sort(v[now].begin(), v[now].end(), cmp);
}

void dfs2(int now) {
    static int tim;
    in[now] = tim++;
    for (int i = 0; i < v[now].size(); i++) {
        ans += tim - in[now];
        dfs2(v[now][i]);
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    cin >> n;
    for (int i = 1; i <= n; i++) cin >> s, insert(s);
    rebuild(root, root);
    dfs(root);
    dfs2(root);
    cout << ans;
    return 0;
}
```

## H HAOI2017 供给侧改革
### Description
[P3732 HAOI2017 供给侧改革](https://www.luogu.com.cn/problem/P3732)

### Solution
在线不太好做，考虑离线处理，将询问按右端点排序,从 $1$ 到 $n$ 枚举起始位 $i$，将起始位置 $i$ 到最后一位的部分插入 $trie$ 树中，然后查询对右端点为 $i$ 的询问的答案。实际上，由于数据随机生成，容易推出最长公共前缀长度不超过40，所以只需要从起始位 $i$ 开始往后插入 $40$ 位就可以了。

对任意位置$i$，记 $pos[k]$ 对应最大左端点，使得 $data(pos[k],i)=k$。显然，$k$ 越大，$pos[k]$ 越小。同时 $trie$ 树上每个节点记一个 $last$，表示上次被访问时对应串的起点位置。插入时，容易算出之前的插入的串和当前串
被插入部分的公共前缀的长度 $l$, 并更新 $pos[l]$ = $\max(pos[l],last)$,对应新的最大左端点。

每次插入后，对所有以 $i$ 为右端点的询问，枚举公共前缀的长度 $k$，根据 $pos$ 中的信息即可求得该询问的答案。

### Code
```cpp HAOI2017 供给侧改革
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int maxn = 100005;
int n, m, pos[50];
// pos[k]对应最大左端点，使得 data(pos[k],i)=k;
//大于pos[k]的位置，data(pos[k],i)<k
char s[maxn];
ll ans[maxn];
struct trie {
    trie* son[2];
    int last;
    trie() {
        son[0] = son[1] = NULL;
        last = 0;
    }
} * root;

struct Question {
    int l, r, qId;
    bool operator<(const Question& other) { return r < other.r; }
} Q[maxn];

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(int st) {
    trie* cur = root;
    for (int i = st; i <= min(st + 39, n); i++) {
        int now = s[i] - '0';
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        if (cur->last) pos[i - st + 1] = max(pos[i - st + 1], cur->last);
        cur->last = st;
    }
}

int main() {
    n = read(), m = read();
    scanf("%s", s + 1);
    for (int i = 1; i <= m; i++) Q[i].l = read(), Q[i].r = read(), Q[i].qId = i;
    sort(Q + 1, Q + m + 1);
    root = new trie;
    for (int i = 1, j = 1; i <= n; i++) {
        insert(i); //插入起始位置在i的串
        while (j <= m && Q[j].r == i) {//以i结尾询问
            for (int k = 1; k <= 40; k++) {//枚举长度
                if (pos[k] >= Q[j].l)// pos[k]在[l,r]内
                    ans[Q[j].qId] +=k * (pos[k] - max(pos[k + 1] + 1, Q[j].l) +1); 
                else
                    break;  
                    // data(pos[k+1]+1,pos[k])=k
                    //由pos单调性可知更大的k都不合法
            }
            j++;  //下一个询问
        }
    }
    for (int i = 1; i <= m; i++) printf("%lld\n", ans[i]);
    return 0;
}
```
## I BJOI2016 IP地址
### Description
[P5460 BJOI2016 IP地址](https://www.luogu.com.cn/problem/P5460)

### Solution
一个 $ip$ 地址在操作 $[l+1,r]$ 匹配到的生效规则变化的次数等于 在 $[1,r]$ 的变化次数**减去** 在$[1,l]$ 的变化次数。容易发现，不论删除还是插入某一规则，在 $trie$ 树中，只会对**当前规则的结尾**和**当前规则结尾往下的第一个结尾**之间的全部节点产生影响。

用 $cnt$ 记录到当前节点匹配到的生效规则变化的次数，$lazyTag$作为延迟下放标记，$endTag$ 记录是否为某条规则的结尾。在插入/删除一个规则时，在结尾处更新 $endTag= endTag + type$($type$ 为 1 表示插入，-1 表示删除)，$cnt++$ 表示匹配到的生效规则发生了一次变化，同时更新 $lazyTag$。插入/删除的同时沿途下放标记，直到遇到下一个结尾停止。  

将操作按 1 到 $n$ 的顺序进行，对于操作 $i$, 可以预处理出哪些询问的左端点或右端点是 $i$。将这些询问的 IP 地址放在当前的 $trie$ 上查询，同时沿途下放标记, 返回末尾处的 $cnt$ 即可求得该 IP 地址在操作$[1,i]$ 匹配到的生效规则变化的次数。如果是左端点，则这个询问的答案应减去 $cnt$; 否则，这个询问的答案应加上 $cnt$。

### Code
```cpp BJOI2016 IP地址
#include <bits/stdc++.h>

using namespace std;
const int maxn = 1e5 + 5;

int n, m;
char opt[4];
string principle[maxn], ip[maxn];
int l[maxn], r[maxn], type[maxn], ans[maxn];
vector<int> vl[maxn], vr[maxn];

struct trie {
    trie* son[2];
    int lazyTag, endTag, cnt;
    trie() {
        son[0] = son[1] = NULL;
        lazyTag = endTag = cnt = 0;
    }
} * root;

void pushDown(trie* cur) {
    if (cur->son[0] == NULL) cur->son[0] = new trie;
    if (cur->son[1] == NULL) cur->son[1] = new trie;

    if (!cur->son[0]->endTag)
        cur->son[0]->lazyTag += cur->lazyTag, cur->son[0]->cnt += cur->lazyTag;
    if (!cur->son[1]->endTag)
        cur->son[1]->lazyTag += cur->lazyTag, cur->son[1]->cnt += cur->lazyTag;

    cur->lazyTag = 0;
}

void insert(const string& s, int type) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        pushDown(cur);
        cur = cur->son[s[i] - '0'];
    }
    cur->endTag += type;
    cur->lazyTag++;
    cur->cnt++;
}

int query(const string& s) {
    trie* cur = root;
    for (int i = 0; i < s.size(); i++) {
        if (cur->son[s[i] - '0'] == NULL) return cur->cnt;
        pushDown(cur);
        cur = cur->son[s[i] - '0'];
    }
    return cur->cnt;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n >> m;
    for (int i = 1; i <= n; i++) {
        cin >> opt >> principle[i];
        type[i] = (opt[0] == 'A' ? 1 : -1);
    }
    for (int i = 1; i <= m; i++) {
        cin >> ip[i] >> l[i] >> r[i];
        vl[l[i]].push_back(i);
        vr[r[i]].push_back(i);
    }
    root = new trie;
    for (int i = 1; i <= n; i++) {
        insert(principle[i], type[i]);
        for (int j = 0; j < vl[i].size(); j++) {
            int id = vl[i][j];
            ans[id] -= query(ip[id]);
        }
        for (int j = 0; j < vr[i].size(); j++) {
            int id = vr[i][j];
            ans[id] += query(ip[id]);
        }
    }
    for (int i = 1; i <= m; i++) cout << ans[i] << endl;
    return 0;
}
```
## J Ynoi2011 竞赛实验班
### Description
[P5312 Ynoi2011 竞赛实验班](https://www.luogu.com.cn/problem/P5312)

### Solution
对于操作 1、3，根据异或运算性质, 开一个全局异或值 $X$ ( 初始为0 ）, 每次将 $X$ 异或上操作 3 给出的 $x$。当插入一个数 $x$ 时，将 $x$ 异或上 $X$ 再插入，这样在查询时再异或上当前的 $X$ 就可以得到插入 $x$ 之后，进行一系列操作 3 后 $x$ 的真实值。

注意到经过操作 4， 任意时刻的序列一定是前半段有序，后半段无序的，这两段对应区间记为 $[1,lastN]$ 和 $[lastN+1,n]$。
实际上，构建出的 $trie$ 树某种程度上说本身就是排好序的，所以对于操作 2，有序的部分可以在 $trie$ 上用类似平衡树查询前缀和的方式；无序的部分可以用二维数组记每一位 1 的个数的前缀和求出，这个前缀和在排序后清零。

综合上述分析，查询应分有两种。具体的，对于无序部分的查询，根据 $X$ 的值，结合前缀和数组，可以推出在 $[lastN+1,n]$ 这段区间上每一位 1 的个数的实际值，一位一位累加可得答案；对于有序的部分，应分别求出前 $lastN$ 个数的和以及前 $l-1$ 个数的和，两者相减可得有序部分 $[l,lastN]$ 的和，详见代码。
### Code
```cpp Ynoi2011 竞赛实验班
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int maxn = 1e5 + 5;
int n, m, type, l, r, X, lastN, lastXor;
int a[maxn * 2], sum[maxn * 2][31];

struct trie {
    trie* son[2];
    int sz;
    int cnt[31];
    trie() {
        son[0] = son[1] = NULL;
        for (int i = 0; i < 31; i++) cnt[i] = 0;
        sz = 0;
    }
} * root;

int read() {
    char ch = getchar();
    int x = 0, f = 1;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    return x * f;
}

void insert(const int& x) {
    trie* cur = root;
    for (int i = 30; i >= 0; i--) {
        int to = (x >> i) & 1;
        if (cur->son[to] == NULL) cur->son[to] = new trie;
        cur = cur->son[to];
        cur->sz++;
        for (int k = 0; k <= 30; ++k) cur->cnt[k] += (x >> k) & 1;
    }
}

ll query2(const int& l, const int& r) {
    ll ans = 0, len = r - l + 1;
    for (int i = 0; i < 31; i++) {
        ll cnt = sum[r][i] - sum[l - 1][i];
        if ((X >> i) & 1) cnt = len - cnt;
        ans += cnt << i;
    }
    return ans;
}

ll query1(int sz) {
    if (!sz) return 0;
    ll ans = 0, val = 0; 
    //val 记录排名第sz的数在当前树中的值，最后实际值要异或全局X
    //ans 在查询的时候已经对X异或过了，最后不需要再异或
    trie* cur = root;
    for (int i = 30; i >= 0; --i) {
        int to = (lastXor >> i) & 1;  //最后一次排序后的异或值
        if (cur->son[to] != NULL && sz <= cur->son[to]->sz)
            cur = cur->son[to], val |= to << i;
        else {
            int sizeOfSon = (cur->son[to] == NULL ? 0 : cur->son[to]->sz);
            //统计son[to]的贡献, 注意用的是当前异或值
            for (int k = 0; k < 31; k++) {
                ll cnt = (cur->son[to] == NULL ? 0 : cur->son[to]->cnt[k]);
                if ((X >> k) & 1) cnt = sizeOfSon - cnt;//实际值要异或X
                ans += cnt << k;
            }
            //走另外一边
            sz -= sizeOfSon;
            cur = cur->son[to ^ 1];
            val |= (to ^ 1) << i;
        }
    }
    return ans + (val ^ X) * sz;  //可能多个数结尾在同一链
}

int main() {
    n = read();
    for (int i = 1; i <= n; i++) {
        a[i] = read();
        for (int k = 0; k < 31; k++)
            sum[i][k] = sum[i - 1][k] + ((a[i] >> k) & 1);
    }
    m = read();
    root = new trie;
    for (int i = 1; i <= m; i++) {
        type = read();
        if (type == 1) {
            a[++n] = read() ^ X;
            for (int k = 0; k < 31; k++)
                sum[n][k] = sum[n - 1][k] + ((a[n] >> k) & 1);
        } else if (type == 2) {
            l = read(), r = read();
            //有序部分用trie处理，无序部分利用前缀和
            if (r <= lastN)
                printf("%lld\n", query1(r) - query1(l - 1));
            else if (l > lastN)
                printf("%lld\n", query2(l, r));
            else
                printf("%lld\n",
                       query1(lastN) - query1(l - 1) + query2(lastN + 1, r));
        } else if (type == 3) {
            X ^= read();
        } else {
            for (int k = lastN + 1; k <= n; k++) insert(a[k]);
            memset(sum[n], 0, sizeof(sum[n]));
            lastN = n, lastXor = X;
        }
    }
    return 0;
}
```
## K Choosing The Commander
### Description
[CF817E Choosing The Commander](https://www.luogu.com.cn/problem/CF817E)

### Solution
插入一个数将其访问过的节点的 $sum++$，删除一个数则 $sum--$。查询时，类似平衡树求 $rank$ 的做法。具体的，记 $l$ 的第 $i$ 位为 $l_i$，$p$ 的第 $i$ 位为 $p_i$。若 $l_i=1$,那么答案应该加上 $son[p_i]$的 $sum$，同时继续查询 $son[p_i⊕1]$；否则继续查询 $son[p_i]$。

### Code
```cpp Choosing The Commander
#include <bits/stdc++.h>

using namespace std;

int n, p, l, type;
struct trie {
    trie* son[2];
    int sum;
    trie() {
        son[0] = son[1] = NULL;
        sum = 0;
    }
} * root;

template <class T>
void read(T& x, int f = 1) {
    char ch = getchar();
    x = 0;
    while (ch < '0' || ch > '9') f = (ch == '-' ? -1 : 1), ch = getchar();
    while (ch >= '0' && ch <= '9') x = x * 10 + ch - 48, ch = getchar();
    x *= f;
}

void insert(int p, int type) {
    trie* cur = root;
    for (int i = 31; ~i; i--) {
        int now = (p >> i) & 1;
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        cur->sum += type;
    }
}

void query(int p, int l) {
    int ans = 0;
    trie* cur = root;
    for (int i = 31; ~i; i--) {
        bool pi = (p >> i) & 1;
        bool li = (l >> i) & 1;
        if (cur == NULL) break;
        if (li && cur->son[pi] != NULL) ans += cur->son[pi]->sum;
        cur = cur->son[pi ^ li];
    }
    printf("%d\n", ans);
}

int main() {
    read(n);
    root = new trie;
    for (int i = 1; i <= n; i++) {
        read(type), read(p);
        if (type == 1)
            insert(p, 1);
        else if (type == 2)
            insert(p, -1);
        else
            read(l), query(p, l);
    }
    return 0;
}
```
## L CF241B Friends
### Description
[CF241B Friends](https://www.luogu.com.cn/problem/CF241B)
### Solution
直接求第 $k$ 不太好处理，因为选取的是无序对，存在选取顺序问题,不然会重复。为了方便可以考虑求所有有序对的异或值，然后求前 $2k$ 大的异或值的和 ，那么答案就是求得的和的一半，这样就不需要考虑重复了。

建立好 $trie$ 树后，用类似平衡树求第 $2k$ 大的方法求出第 $2k$ 大的两两异或值 $valKth$，同时可以得到这样的值有多少个。接下来于对每一个数 $val[i]$，在 $trie$ 树上，求与之异或后大于 $valKth$ 的数的和。具体的，若 $valkth$ 第 $j$ 位为 1，那么接下来应该访问和 $val[i]$ 第 $j$ 位互补的那个儿子；否则，应该访问$val[i]$ 第 $j$ 位相同的儿子，同时统计与 $val[i]$ 在第 $j$ 位异或值为 1 的值的和。具体的统计方法是，在预处理时将 $val$ 数组排序，记录每一位上 0/1 数量的前缀和，在插入时记录每个节点对应 $val$ 的下标范围，之后根据这个范围内每一位(设为 $p$)  0/1 的个数以及 $val[i]$ 的第 $p$ 位的值按位求和即可。
### Code
```cpp CF241B Friends
#include <bits/stdc++.h>

using namespace std;
typedef long long ll;

const int MAXN = 5e4 + 5;
const int MOD = 1e9 + 7;
const int BIT = 30;
int n, val[MAXN];
ll k, pre[MAXN][BIT + 2][2];  //每一位上0,1的个数前缀和

struct trie {
    trie* son[2];
    int sz, mx, mi;
    trie() {
        son[0] = son[1] = NULL;
        sz = mx = mi = 0;
    }
} * root;

ll qpow(ll a, ll b) {
    ll ans = 1, base = a;
    while (b) {
        if (b & 1) ans = ans * base % MOD;
        b >>= 1, base = base * base % MOD;
    }
    return ans;
}

void insert(int& id) {
    trie* cur = root;
    for (int i = BIT; ~i; i--) {
        int now = (val[id] >> i) & 1;
        if (cur->son[now] == NULL) cur->son[now] = new trie;
        cur = cur->son[now];
        cur->sz++;
        cur->mx = id;
        cur->mi = (cur->mi ? cur->mi : id);
    }
}

ll getKth(ll& k) {
    ll ans = 0;
    trie* nodePtr[MAXN];
    for (int i = 1; i <= n; i++) nodePtr[i] = root;
    for (int j = BIT; ~j; j--) {
        ll tmp = 0;
        bool tag = 1;
        for (int i = 1; i <= n; i++)
            if (nodePtr[i] != NULL &&
                nodePtr[i]->son[((val[i] >> j) & 1) ^ 1] != NULL)
                tmp += nodePtr[i]->son[((val[i] >> j) & 1) ^ 1]->sz;
        if (tmp >= k)  //该位选1的方案数>=k，则第k大的在这一位必为1
            ans |= 1ll << j;
        else  //该位选1的方案数<k，则第k大的在这一位必为0，且排名<=k-该位选1的方案数
            k -= tmp, tag = 0;
        for (int i = 1; i <= n; i++)
            if (nodePtr[i])
                nodePtr[i] = nodePtr[i]->son[((val[i] >> j) & 1) ^ tag];
    }
    return ans;
}

void getSum(ll k) {
    ll valKth = getKth(k);
    ll ans = valKth * k % MOD;
    for (int i = 1; i <= n; i++) {
        //对于每一个数，求与之异或后大于valKth的数的和
        trie* cur = root;
        for (int j = BIT; ~j; j--) {
            if (cur == NULL) break;
            if ((valKth >> j) & 1)
                cur = cur->son[((val[i] >> j) & 1) ^ 1];
            else {
                if (cur->son[((val[i] >> j) & 1) ^ 1] != NULL) {
                    int l = cur->son[((val[i] >> j) & 1) ^ 1]->mi - 1;
                    int r = cur->son[((val[i] >> j) & 1) ^ 1]->mx;
                    for (int p = BIT; ~p; p--) {
                        if ((val[i] >> p) & 1)
                            ans += (pre[r][p][0] - pre[l][p][0]) << p;
                        else
                            ans += (pre[r][p][1] - pre[l][p][1]) << p;
                        ans %= MOD;
                    }
                }
                cur = cur->son[(val[i] >> j) & 1];
            }
        }
    }
    cout << ans * qpow(2, MOD - 2) % MOD;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0), cout.tie(0);
    cin >> n >> k;
    k *= 2;
    for (int i = 1; i <= n; i++) cin >> val[i];
    sort(val + 1, val + n + 1);
    root = new trie;
    for (int i = 1; i <= n; i++) insert(i);
    for (int j = BIT; ~j; j--)
        for (int i = 1; i <= n; i++) {
            pre[i][j][0] = pre[i - 1][j][0] + !((val[i] >> j) & 1);
            pre[i][j][1] = pre[i - 1][j][1] + ((val[i] >> j) & 1);
        }
    getSum(k);
    return 0;
}
```

