}

int main() {
    ios::sync_with_stdio(false), cin.tie(0), cout.tie(0);
    cin >> testCase;
    while (testCase--) {
        cin >> n >> L;
        for (int i = 1; i <= n; i++) cin >> vec[i].x >> vec[i].y;
        double res = convex() + PI * 2 * L;
        cout << setprecision(0) << fixed << res << endl;
        if (testCase) cout << endl;
    }
    return 0;
}
